<template>
  <div class="college-detail-page">
    <el-page-header @back="$router.back()" :title="'返回'" class="page-header">
      <template #default>
        <span class="header-title">{{ collegeName }}</span>
      </template>
    </el-page-header>

    <el-tabs v-model="activeTab" class="detail-tabs" v-if="detail">
      <!-- 基本信息 -->
      <el-tab-pane label="基本信息" name="basic">
        <el-descriptions :column="2" border class="meta-desc">
          <el-descriptions-item label="院校名称">{{ detail.name }}</el-descriptions-item>
          <el-descriptions-item label="所在城市">{{ detail.city }}</el-descriptions-item>
          <el-descriptions-item label="所在省份">{{ detail.province }}</el-descriptions-item>
          <el-descriptions-item label="所属区域">{{ detail.region }}</el-descriptions-item>
          <el-descriptions-item label="学费区间">
            {{ detail.tuitionRange.min }} - {{ detail.tuitionRange.max }} 元/年
          </el-descriptions-item>
          <el-descriptions-item label="院校标签">
            <div class="tag-group">
              <el-tag v-if="detail.tags.is985" type="danger" size="small">985</el-tag>
              <el-tag v-if="detail.tags.is211" type="warning" size="small">211</el-tag>
              <el-tag v-if="detail.tags.isDoubleFirstClass" type="success" size="small">双一流</el-tag>
              <el-tag v-if="!detail.tags.isPublic" size="small">民办</el-tag>
              <el-tag v-else type="success" size="small">公办</el-tag>
            </div>
          </el-descriptions-item>
        </el-descriptions>

        <!-- 专业组列表 -->
        <div class="groups-section" v-if="detail.groups.length > 0">
          <h3>专业组</h3>
          <el-table :data="detail.groups" stripe border>
            <el-table-column prop="groupName" label="专业组名称" min-width="180" />
            <el-table-column prop="selectRequirement" label="选科要求" min-width="150" />
            <el-table-column prop="majorCount" label="专业数" width="80" align="center" />
            <el-table-column prop="planCount" label="计划数" width="80" align="center" />
          </el-table>
        </div>
      </el-tab-pane>

      <!-- 就业前景 -->
      <el-tab-pane label="就业前景" name="employment">
        <EmploymentSummary :data="employmentRecords" />
      </el-tab-pane>

      <!-- 升学深造 -->
      <el-tab-pane label="升学深造" name="postgraduate">
        <PostgraduateSummary :data="postgraduateRecords" />
      </el-tab-pane>

      <!-- 历年数据 -->
      <el-tab-pane label="历年录取" name="admissions">
        <div v-if="detail.admissions.length === 0" class="empty-state">
          <el-empty description="暂无录取数据" />
        </div>
        <el-table v-else :data="detail.admissions" stripe border>
          <el-table-column prop="year" label="年份" width="80" align="center" />
          <el-table-column prop="group_name" label="专业组" min-width="150" />
          <el-table-column label="最低分/位次" width="160">
            <template #default="{ row }">
              {{ row.lowest_score }} / {{ row.lowest_position?.toLocaleString() }}
            </template>
          </el-table-column>
          <el-table-column label="平均分/位次" width="160">
            <template #default="{ row }">
              {{ row.avg_score }} / {{ row.avg_position?.toLocaleString() }}
            </template>
          </el-table-column>
          <el-table-column label="最高分/位次" width="160">
            <template #default="{ row }">
              {{ row.highest_score }} / {{ row.highest_position?.toLocaleString() }}
            </template>
          </el-table-column>
        </el-table>
      </el-tab-pane>
    </el-tabs>

    <div v-else class="loading-state">
      <el-skeleton :rows="6" animated />
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted } from 'vue';
import { useRoute } from 'vue-router';
import axios from 'axios';
import EmploymentSummary from '@/components/EmploymentSummary.vue';
import PostgraduateSummary from '@/components/PostgraduateSummary.vue';

const route = useRoute();
const collegeId = computed(() => route.params.id as string);

interface CollegeDetail {
  id: string;
  name: string;
  city: string;
  province: string;
  region: string;
  tags: { is985: boolean; is211: boolean; isDoubleFirstClass: boolean; isPublic: boolean };
  tuitionRange: { min: number; max: number };
  groups: { id: string; groupName: string; selectRequirement?: string; majorCount: number; planCount: number }[];
  admissions: any[];
  employment: any[];
  postgraduate: any[];
}

const activeTab = ref('basic');
const detail = ref<CollegeDetail | null>(null);

const employmentRecords = computed(() => {
  return (detail.value?.employment ?? []).map((r: any) => ({
    ...r,
    employers_parsed: parseJsonField(r.employers),
  }));
});

const postgraduateRecords = computed(() => {
  return (detail.value?.postgraduate ?? []).map((r: any) => ({
    ...r,
    target_schools_parsed: parseJsonField(r.target_schools),
  }));
});

function parseJsonField(raw: string): any {
  if (!raw) return [];
  try {
    return JSON.parse(raw);
  } catch {
    return [];
  }
}

const collegeName = computed(() => detail.value?.name ?? '加载中...');

onMounted(async () => {
  try {
    const { data } = await axios.get(`/api/colleges/${collegeId.value}`);
    if (data.code === 0) {
      const raw = data.data;
      detail.value = {
        id: raw.college?.id ?? raw.college?.name ?? collegeId.value,
        name: raw.college?.name ?? '',
        city: raw.college?.city ?? '',
        province: raw.college?.province ?? '',
        region: raw.college?.region ?? '',
        tags: {
          is985: !!raw.college?.is_985,
          is211: !!raw.college?.is_211,
          isDoubleFirstClass: !!raw.college?.is_double_first_class,
          isPublic: !!raw.college?.is_public,
        },
        tuitionRange: {
          min: raw.college?.tuition_min ?? 0,
          max: raw.college?.tuition_max ?? 0,
        },
        groups: (raw.groups ?? []).map((g: any) => ({
          id: g.id,
          groupName: g.group_name,
          selectRequirement: g.select_requirement,
          majorCount: g.major_count,
          planCount: g.plan_count,
        })),
        admissions: raw.admissions ?? [],
        employment: raw.employment ?? [],
        postgraduate: raw.postgraduate ?? [],
      };
    }
  } catch (err) {
    console.error('Failed to load college detail:', err);
  }
});
</script>

