<template>
  <div class="employment-summary">
    <el-empty v-if="!data || data.length === 0" description="暂无就业数据" :image-size="100" />

    <template v-else>
      <!-- 汇总卡片 -->
      <el-row :gutter="16" class="summary-row">
        <el-col :span="12">
          <el-card shadow="hover" class="stat-card">
            <div class="stat-label">综合就业率</div>
            <div class="stat-value" :class="rateClass(latestRate)">
              {{ latestRate?.toFixed(1) ?? '--' }}%
            </div>
          </el-card>
        </el-col>
        <el-col :span="12">
          <el-card shadow="hover" class="stat-card">
            <div class="stat-label">平均起薪</div>
            <div class="stat-value">
              ¥{{ latestAvg?.toLocaleString() ?? '--' }}/月
            </div>
          </el-card>
        </el-col>
      </el-row>

      <!-- 按行业分类 -->
      <div class="category-tabs">
        <el-tabs v-model="activeCategory" type="card" @tab-change="onTabChange">
          <el-tab-pane
            v-for="item in data"
            :key="item.id"
            :label="item.category"
            :name="item.id"
          />
        </el-tabs>
      </div>

      <!-- 当前选中分类的雇主列表 -->
      <div v-if="currentEmployment" class="employer-list">
        <el-descriptions title="行业分类" :column="2" border class="meta-desc">
          <el-descriptions-item label="分类">{{ currentEmployment.category }}</el-descriptions-item>
          <el-descriptions-item label="数据年份">{{ currentEmployment.dataYear }}</el-descriptions-item>
        </el-descriptions>

        <el-table :data="[currentEmployment]" stripe border class="employer-table">
          <el-table-column label="雇主" min-width="160">
            <template #default="{ row }">
              <div v-for="e in (row.employers_parsed || [])" :key="e.name" class="employer-item">
                <div class="employer-name">{{ e.name }}</div>
                <div class="employer-positions">{{ e.positions.join('、') }}</div>
              </div>
            </template>
          </el-table-column>
          <el-table-column label="薪资范围" min-width="180">
            <template #default="{ row }">
              <div v-for="e in (row.employers_parsed || [])" :key="e.name" class="salary-range">
                <span>{{ e.name }}</span>
                <el-progress
                  :percentage="salaryPercent(e)"
                  :format="() => `¥${(e.salaryMin||0).toLocaleString()} - ¥${(e.salaryMax||0).toLocaleString()}`"
                  :stroke-width="14"
                  :show-text="true"
                />
              </div>
            </template>
          </el-table-column>
        </el-table>
      </div>
    </template>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from 'vue';

interface EmployerItem {
  name: string;
  positions: string[];
  salaryMin?: number;
  salaryMax?: number;
}

interface EmploymentRecord {
  id: string;
  collegeGroupId: string;
  dataYear: number;
  category: string;
  employers: string; // JSON string from API
  employmentRate?: number;
  avgSalary?: number;
}

const props = defineProps<{ data: EmploymentRecord[] }>();

const activeCategory = ref<string>('');

const latestRate = computed(() => {
  if (props.data.length === 0) return undefined;
  const latest = [...props.data].sort((a, b) => b.dataYear - a.dataYear)[0];
  return latest.employmentRate;
});

const latestAvg = computed(() => {
  if (props.data.length === 0) return undefined;
  const latest = [...props.data].sort((a, b) => b.dataYear - a.dataYear)[0];
  return latest.avgSalary;
});

const currentEmployment = computed(() => {
  if (!activeCategory.value) return null;
  return props.data.find(d => d.id === activeCategory.value) ?? null;
});

function rateClass(rate?: number): string {
  if (!rate) return '';
  if (rate >= 95) return 'rate-high';
  if (rate >= 90) return 'rate-medium';
  return 'rate-low';
}

function salaryPercent(e: EmployerItem): number {
  const max = e.salaryMax ?? 30000;
  const min = e.salaryMin ?? 8000;
  return Math.round(((max - min) / max) * 100);
}

function onTabChange() {
  // tab switched
}

// 初始化默认选中第一个
if (props.data.length > 0) {
  activeCategory.value = props.data[0].id;
}
</script>

