<template>
  <div class="postgraduate-summary">
    <el-empty v-if="!data || data.length === 0" description="暂无升学数据" :image-size="100" />

    <template v-else>
      <!-- 汇总卡片 -->
      <el-row :gutter="16" class="summary-row">
        <el-col :span="8">
          <el-card shadow="hover" class="stat-card">
            <div class="stat-label">升学率</div>
            <div class="stat-value" :class="rateClass(latestRate)">
              {{ latestRate?.toFixed(1) ?? '--' }}%
            </div>
          </el-card>
        </el-col>
        <el-col :span="8">
          <el-card shadow="hover" class="stat-card">
            <div class="stat-label">国内升学</div>
            <div class="stat-value">{{ latestDomestic?.toFixed(1) ?? '--' }}%</div>
          </el-card>
        </el-col>
        <el-col :span="8">
          <el-card shadow="hover" class="stat-card">
            <div class="stat-label">出国深造</div>
            <div class="stat-value">{{ latestOverseas?.toFixed(1) ?? '--' }}%</div>
          </el-card>
        </el-col>
      </el-row>

      <!-- 考研难度 -->
      <el-card shadow="never" class="difficulty-card" v-if="currentData">
        <template #header>
          <span>考研难度</span>
          <el-tag :type="difficultyType(currentData.examDifficulty)" effect="dark" size="large" class="difficulty-badge">
            {{ difficultyLabel(currentData.examDifficulty) }}
          </el-tag>
        </template>
        <div class="difficulty-notes" v-if="currentData.examNotes">
          {{ currentData.examNotes }}
        </div>
      </el-card>

      <!-- 目标学校列表 -->
      <el-card shadow="never" class="schools-card" v-if="currentData">
        <template #header>
          <span>主要升学去向</span>
        </template>
        <el-table :data="schoolRows" stripe border>
          <el-table-column prop="school" label="目标院校" min-width="160" />
          <el-table-column label="占比" width="200">
            <template #default="{ row }">
              <div class="school-bar">
                <span>{{ row.rate }}%</span>
                <el-progress
                  :percentage="row.rate"
                  :color="getSchoolColor(row.rate)"
                  :show-text="false"
                  :stroke-width="8"
                />
              </div>
            </template>
          </el-table-column>
        </el-table>
      </el-card>
    </template>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from 'vue';

interface TargetSchoolItem {
  school: string;
  rate: number;
}

interface PostgraduateRecord {
  id: string;
  collegeGroupId: string;
  dataYear: number;
  advancementRate: number;
  domesticRate: number;
  overseasRate: number;
  targetSchools: string; // JSON string
  examDifficulty: string;
  examNotes?: string;
}

const props = defineProps<{ data: PostgraduateRecord[] }>();

const activeYear = ref<number>(0);

const latestRate = computed(() => {
  if (props.data.length === 0) return undefined;
  return props.data[0]?.advancementRate;
});

const latestDomestic = computed(() => {
  if (props.data.length === 0) return undefined;
  return props.data[0]?.domesticRate;
});

const latestOverseas = computed(() => {
  if (props.data.length === 0) return undefined;
  return props.data[0]?.overseasRate;
});

const currentData = computed(() => {
  if (props.data.length === 0) return null;
  if (activeYear.value === 0) {
    activeYear.value = props.data[0].dataYear;
  }
  return props.data.find(d => d.dataYear === activeYear.value) ?? props.data[0];
});

const schoolRows = computed(() => {
  if (!currentData.value) return [];
  try {
    return JSON.parse(currentData.value.targetSchools) as TargetSchoolItem[];
  } catch {
    return [];
  }
});

function rateClass(rate?: number): string {
  if (!rate) return '';
  if (rate >= 40) return 'rate-high';
  if (rate >= 25) return 'rate-medium';
  return 'rate-low';
}

function difficultyType(level: string): 'success' | 'warning' | 'danger' | 'info' {
  const map: Record<string, 'success' | 'warning' | 'danger' | 'info'> = {
    easy: 'success',
    moderate: 'warning',
    hard: 'danger',
    very_hard: 'danger',
  };
  return map[level] ?? 'info';
}

function difficultyLabel(level: string): string {
  const map: Record<string, string> = {
    easy: '容易',
    moderate: '一般',
    hard: '较难',
    very_hard: '很难',
  };
  return map[level] ?? level;
}

function getSchoolColor(rate: number): string {
  if (rate >= 30) return '#67c23a';
  if (rate >= 15) return '#e6a23c';
  return '#909399';
}
</script>

